mapper.select:
SELECT ers.id, ers.student_name, ers.exam_id, ers.score, p.name AS paper_name, p.total_score AS paper_total_score, ers.start_time, ers.end_time, TIMESTAMPDIFF(MINUTE, ers.start_time, ers.end_time) AS duration FROM exam_records ers JOIN paper p ON ers.exam_id = p.id
ers.status = '已批阅' AND ers.is_deleted = 0 AND p.is_deleted = 0
AND p.id = #{paperId}
ORDER BY ers.score DESC, duration ASC
LIMIT #{limit}
